INSERT IGNORE INTO fs_tutorial (id, title, summary, cover_url, author_id, status, view_count, like_count, sort_order, published_at, deleted) VALUES
    (1001, '算法训练题集：从基础结构到动态规划与图论', '按照数组、链表、哈希、字符串、双指针、栈队列、树、回溯、贪心、动态规划、单调栈和图论组织的函数签名式算法训练路线。', NULL, NULL, 'PUBLISHED', 0, 0, 1, NOW(), 0);
INSERT IGNORE INTO fs_blog (id, tutorial_id, title, content_md, summary, cover_url, author_id, sort_order, estimated_minutes, status, view_count, like_count, published_at, deleted) VALUES
    (2001, 1001, '数组基础与区间思维', '## 学习目标\n\n- 理解「数组」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n数组是多数算法题的起点，重点训练下标、边界、二分、窗口和连续区间等基础能力。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '数组是多数算法题的起点，重点训练下标、边界、二分、窗口和连续区间等基础能力。', NULL, NULL, 1, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2002, 1001, '链表指针操作与虚拟头节点', '## 学习目标\n\n- 理解「链表」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n链表题强调节点关系变化，适合训练指针保存、虚拟头节点和一次遍历技巧。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '链表题强调节点关系变化，适合训练指针保存、虚拟头节点和一次遍历技巧。', NULL, NULL, 2, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2003, 1001, '哈希映射与集合去重', '## 学习目标\n\n- 理解「哈希表」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n哈希表适合解决快速查找、计数、去重和映射关系问题。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '哈希表适合解决快速查找、计数、去重和映射关系问题。', NULL, NULL, 3, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2004, 1001, '字符串基本操作与局部重排', '## 学习目标\n\n- 理解「字符串」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n字符串题常见考点包括切分、反转、字符统计和原地处理。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '字符串题常见考点包括切分、反转、字符统计和原地处理。', NULL, NULL, 4, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2005, 1001, '双指针与有序结构处理', '## 学习目标\n\n- 理解「双指针法」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n双指针可以降低嵌套循环复杂度，常用于有序数组、快慢指针和原地调整。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '双指针可以降低嵌套循环复杂度，常用于有序数组、快慢指针和原地调整。', NULL, NULL, 5, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2006, 1001, '栈队列模拟与单调结构前置', '## 学习目标\n\n- 理解「栈与队列」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n栈适合处理匹配和最近关系，队列适合处理窗口与层序遍历。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '栈适合处理匹配和最近关系，队列适合处理窗口与层序遍历。', NULL, NULL, 6, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2007, 1001, '二叉树递归与层序建模', '## 学习目标\n\n- 理解「二叉树」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n二叉树训练递归定义、空节点处理、深度计算和结构判断。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '二叉树训练递归定义、空节点处理、深度计算和结构判断。', NULL, NULL, 7, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2008, 1001, '回溯搜索与组合枚举', '## 学习目标\n\n- 理解「回溯算法」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n回溯用于构造所有可行方案，核心是路径、选择列表和撤销选择。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '回溯用于构造所有可行方案，核心是路径、选择列表和撤销选择。', NULL, NULL, 8, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2009, 1001, '局部选择与可行性维护', '## 学习目标\n\n- 理解「贪心算法」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n贪心需要证明局部选择不会破坏全局最优，适合区间、跳跃和资源分配问题。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '贪心需要证明局部选择不会破坏全局最优，适合区间、跳跃和资源分配问题。', NULL, NULL, 9, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2010, 1001, '状态定义、转移与初始化', '## 学习目标\n\n- 理解「动态规划」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n动态规划通过状态保存子问题答案，重点是状态含义、递推公式和遍历顺序。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '动态规划通过状态保存子问题答案，重点是状态含义、递推公式和遍历顺序。', NULL, NULL, 10, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2011, 1001, '单调栈与最近更大关系', '## 学习目标\n\n- 理解「单调栈」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n单调栈适合寻找某个元素左右两侧第一个更大或更小元素。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '单调栈适合寻找某个元素左右两侧第一个更大或更小元素。', NULL, NULL, 11, 8, 'PUBLISHED', 0, 0, NOW(), 0),
    (2012, 1001, '网格图、邻接表与拓扑关系', '## 学习目标\n\n- 理解「图论」专题中的核心数据结构或算法模式。\n- 能够根据输入规模选择合适的时间复杂度。\n- 通过函数签名式题目训练参数建模、返回值处理和边界条件判断。\n\n## 核心概念\n\n图论题训练连通性、遍历、入度和依赖关系建模。\n\n本专题的题目不强调背诵模板，而是强调把问题转化为清晰的状态、指针、容器或搜索过程。解题时先判断输入规模，再决定是否需要哈希、双指针、递归、动态规划或图遍历。\n\n## 示例\n\n遇到题目时，可以先写出函数签名、参数含义和返回值含义，再根据样例手动模拟一次。这样可以减少下标越界、空输入和返回格式错误。\n\n## 常见问题\n\n- 是否需要额外空间：看题目是否要求原地修改。\n- 是否存在多个正确答案：当前题集尽量设计为唯一输出，便于简单判题。\n- 是否需要排序：如果排序会改变原题语义，需要先确认是否允许。\n\n## 练习建议\n\n先完成简单题，再完成同专题的中等题。每道题通过后，建议复盘边界输入和失败测试。\n', '图论题训练连通性、遍历、入度和依赖关系建模。', NULL, NULL, 12, 8, 'PUBLISHED', 0, 0, NOW(), 0);
INSERT IGNORE INTO fs_problem (id, blog_id, title, description_md, difficulty, input_description, output_description, support_languages, time_limit_ms, memory_limit_mb, status, submit_count, accepted_count, sort_order, deleted) VALUES
    (3001, 2001, '搜索插入位置', '## 题目描述\n\n    给定一个严格递增的整数数组和一个目标值，返回目标值应当插入的位置下标。如果目标值已经存在，返回其当前下标。\n\n    ## 函数签名\n\n    - Java：`public int searchInsert(int[] nums, int target)`\n    - Python：`def searchInsert(self, nums, target)`\n\n    ## 输入格式\n\n    第一行输入整数 n；第二行输入 n 个递增整数；第三行输入 target。\n\n    ## 输出格式\n\n    输出一个整数，表示插入位置下标。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    4\n1 3 5 6\n5\n    ~~~\n\n    输出：\n\n    ~~~text\n    2\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 10000\n- 数组严格递增\n- -10^9 <= target <= 10^9', 'EASY', '第一行输入整数 n；第二行输入 n 个递增整数；第三行输入 target。', '输出一个整数，表示插入位置下标。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3002, 2001, '长度最小的连续子数组', '## 题目描述\n\n    给定一个正整数 target 和一个正整数数组，找出总和大于等于 target 的最短连续子数组长度。如果不存在这样的子数组，返回 0。\n\n    ## 函数签名\n\n    - Java：`public int minSubArrayLen(int target, int[] nums)`\n    - Python：`def minSubArrayLen(self, target, nums)`\n\n    ## 输入格式\n\n    第一行输入 n 和 target；第二行输入 n 个正整数。\n\n    ## 输出格式\n\n    输出最短连续子数组长度。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    6 7\n2 3 1 2 4 3\n    ~~~\n\n    输出：\n\n    ~~~text\n    2\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 100000\n- 1 <= nums[i], target <= 10^9', 'MEDIUM', '第一行输入 n 和 target；第二行输入 n 个正整数。', '输出最短连续子数组长度。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3003, 2002, '反转链表', '## 题目描述\n\n    给定一个单链表的头节点，返回反转后的链表头节点。\n\n    ## 函数签名\n\n    - Java：`public ListNode reverseList(ListNode head)`\n    - Python：`def reverseList(self, head)`\n\n    ## 输入格式\n\n    第一行输入链表节点数量 n；第二行输入 n 个节点值。n 为 0 时第二行可以为空。\n\n    ## 输出格式\n\n    按链表顺序输出反转后的节点值，使用空格分隔；空链表输出空行。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    5\n1 2 3 4 5\n    ~~~\n\n    输出：\n\n    ~~~text\n    5 4 3 2 1\n    ~~~\n\n    ## 数据范围\n\n    - 0 <= n <= 10000\n- 节点值为整数', 'EASY', '第一行输入链表节点数量 n；第二行输入 n 个节点值。n 为 0 时第二行可以为空。', '按链表顺序输出反转后的节点值，使用空格分隔；空链表输出空行。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3004, 2002, '删除链表倒数第 N 个节点', '## 题目描述\n\n    给定一个单链表和整数 n，删除链表倒数第 n 个节点，并返回新的头节点。\n\n    ## 函数签名\n\n    - Java：`public ListNode removeNthFromEnd(ListNode head, int n)`\n    - Python：`def removeNthFromEnd(self, head, n)`\n\n    ## 输入格式\n\n    第一行输入链表节点数量 len；第二行输入 len 个节点值；第三行输入 n。\n\n    ## 输出格式\n\n    输出删除后的链表节点值，使用空格分隔；空链表输出空行。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    5\n1 2 3 4 5\n2\n    ~~~\n\n    输出：\n\n    ~~~text\n    1 2 3 5\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= len <= 10000\n- 1 <= n <= len', 'MEDIUM', '第一行输入链表节点数量 len；第二行输入 len 个节点值；第三行输入 n。', '输出删除后的链表节点值，使用空格分隔；空链表输出空行。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3005, 2003, '有效的字母异位词', '## 题目描述\n\n    给定两个只包含小写字母的字符串，判断它们是否由相同字符以不同顺序组成。\n\n    ## 函数签名\n\n    - Java：`public boolean isAnagram(String s, String t)`\n    - Python：`def isAnagram(self, s, t)`\n\n    ## 输入格式\n\n    第一行输入字符串 s；第二行输入字符串 t。\n\n    ## 输出格式\n\n    若二者互为字母异位词，输出 true，否则输出 false。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    anagram\nnagaram\n    ~~~\n\n    输出：\n\n    ~~~text\n    true\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= 字符串长度 <= 50000\n- 只包含小写英文字母', 'EASY', '第一行输入字符串 s；第二行输入字符串 t。', '若二者互为字母异位词，输出 true，否则输出 false。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3006, 2003, '两个数组的唯一交集', '## 题目描述\n\n    给定两个整数数组，返回它们的唯一交集。为了便于判题，输出结果按升序排列。\n\n    ## 函数签名\n\n    - Java：`public int[] intersection(int[] nums1, int[] nums2)`\n    - Python：`def intersection(self, nums1, nums2)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 nums1；第三行输入 m；第四行输入 nums2。\n\n    ## 输出格式\n\n    输出升序排列后的唯一交集，使用空格分隔；没有交集输出空行。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    4\n1 2 2 1\n2\n2 2\n    ~~~\n\n    输出：\n\n    ~~~text\n    2\n    ~~~\n\n    ## 数据范围\n\n    - 0 <= n, m <= 10000\n- 数组元素为整数', 'EASY', '第一行输入 n；第二行输入 nums1；第三行输入 m；第四行输入 nums2。', '输出升序排列后的唯一交集，使用空格分隔；没有交集输出空行。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3007, 2004, '反转字符串中的单词', '## 题目描述\n\n    给定一个字符串，反转其中单词的顺序。单词之间可能有多个空格，结果中单词之间只保留一个空格，首尾不保留空格。\n\n    ## 函数签名\n\n    - Java：`public String reverseWords(String s)`\n    - Python：`def reverseWords(self, s)`\n\n    ## 输入格式\n\n    输入一整行字符串 s。\n\n    ## 输出格式\n\n    输出处理后的字符串。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    the sky is blue\n    ~~~\n\n    输出：\n\n    ~~~text\n    blue is sky the\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= s.length <= 100000\n- 字符串可能包含空格和可见字符', 'MEDIUM', '输入一整行字符串 s。', '输出处理后的字符串。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3008, 2004, '左旋转字符串', '## 题目描述\n\n    给定字符串 s 和整数 k，将字符串左侧的 k 个字符移动到字符串末尾。k 可能大于字符串长度。\n\n    ## 函数签名\n\n    - Java：`public String rotateLeft(String s, int k)`\n    - Python：`def rotateLeft(self, s, k)`\n\n    ## 输入格式\n\n    第一行输入字符串 s；第二行输入整数 k。\n\n    ## 输出格式\n\n    输出左旋转后的字符串。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    abcdefg\n2\n    ~~~\n\n    输出：\n\n    ~~~text\n    cdefgab\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= s.length <= 100000\n- 0 <= k <= 10^9', 'EASY', '第一行输入字符串 s；第二行输入整数 k。', '输出左旋转后的字符串。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3009, 2005, '移动零', '## 题目描述\n\n    给定一个整数数组，将所有 0 移动到数组末尾，同时保持非零元素的相对顺序。要求在原数组上修改。\n\n    ## 函数签名\n\n    - Java：`public void moveZeroes(int[] nums)`\n    - Python：`def moveZeroes(self, nums)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 n 个整数。\n\n    ## 输出格式\n\n    输出修改后的数组，使用空格分隔。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    5\n0 1 0 3 12\n    ~~~\n\n    输出：\n\n    ~~~text\n    1 3 12 0 0\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 10000\n- 数组元素为整数', 'EASY', '第一行输入 n；第二行输入 n 个整数。', '输出修改后的数组，使用空格分隔。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3010, 2005, '有序数组的平方', '## 题目描述\n\n    给定一个非递减排序的整数数组，返回每个数平方后组成的新数组，要求结果仍然非递减。\n\n    ## 函数签名\n\n    - Java：`public int[] sortedSquares(int[] nums)`\n    - Python：`def sortedSquares(self, nums)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 n 个非递减整数。\n\n    ## 输出格式\n\n    输出平方后非递减数组，使用空格分隔。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    5\n-4 -1 0 3 10\n    ~~~\n\n    输出：\n\n    ~~~text\n    0 1 9 16 100\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 10000\n- -10000 <= nums[i] <= 10000', 'EASY', '第一行输入 n；第二行输入 n 个非递减整数。', '输出平方后非递减数组，使用空格分隔。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3011, 2006, '有效括号序列', '## 题目描述\n\n    给定只包含小括号、中括号和大括号的字符串，判断括号是否按正确顺序闭合。\n\n    ## 函数签名\n\n    - Java：`public boolean isValid(String s)`\n    - Python：`def isValid(self, s)`\n\n    ## 输入格式\n\n    输入一行括号字符串 s。\n\n    ## 输出格式\n\n    若有效输出 true，否则输出 false。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    ()[]{}\n    ~~~\n\n    输出：\n\n    ~~~text\n    true\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= s.length <= 100000\n- s 只包含 ()[]{}', 'EASY', '输入一行括号字符串 s。', '若有效输出 true，否则输出 false。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3012, 2006, '滑动窗口最大值', '## 题目描述\n\n    给定整数数组和窗口大小 k，窗口每次向右移动一位，返回每个窗口中的最大值。\n\n    ## 函数签名\n\n    - Java：`public int[] maxSlidingWindow(int[] nums, int k)`\n    - Python：`def maxSlidingWindow(self, nums, k)`\n\n    ## 输入格式\n\n    第一行输入 n 和 k；第二行输入 n 个整数。\n\n    ## 输出格式\n\n    输出每个窗口最大值，使用空格分隔。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    8 3\n1 3 -1 -3 5 3 6 7\n    ~~~\n\n    输出：\n\n    ~~~text\n    3 3 5 5 6 7\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= k <= n <= 100000', 'HARD', '第一行输入 n 和 k；第二行输入 n 个整数。', '输出每个窗口最大值，使用空格分隔。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3013, 2007, '二叉树最大深度', '## 题目描述\n\n    给定一棵二叉树，返回从根节点到最远叶子节点的最大节点数。输入使用层序序列，null 表示空节点。\n\n    ## 函数签名\n\n    - Java：`public int maxDepth(TreeNode root)`\n    - Python：`def maxDepth(self, root)`\n\n    ## 输入格式\n\n    输入一行层序序列，节点之间使用空格分隔，空节点使用 null。空树输入 null。\n\n    ## 输出格式\n\n    输出最大深度。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    3 9 20 null null 15 7\n    ~~~\n\n    输出：\n\n    ~~~text\n    3\n    ~~~\n\n    ## 数据范围\n\n    - 节点数 0 到 10000\n- 节点值为整数', 'EASY', '输入一行层序序列，节点之间使用空格分隔，空节点使用 null。空树输入 null。', '输出最大深度。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3014, 2007, '对称二叉树', '## 题目描述\n\n    给定一棵二叉树，判断它是否关于根节点左右对称。输入使用层序序列，null 表示空节点。\n\n    ## 函数签名\n\n    - Java：`public boolean isSymmetric(TreeNode root)`\n    - Python：`def isSymmetric(self, root)`\n\n    ## 输入格式\n\n    输入一行层序序列，节点之间使用空格分隔，空节点使用 null。\n\n    ## 输出格式\n\n    若对称输出 true，否则输出 false。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    1 2 2 3 4 4 3\n    ~~~\n\n    输出：\n\n    ~~~text\n    true\n    ~~~\n\n    ## 数据范围\n\n    - 节点数 0 到 10000\n- 节点值为整数', 'EASY', '输入一行层序序列，节点之间使用空格分隔，空节点使用 null。', '若对称输出 true，否则输出 false。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3015, 2008, '组合', '## 题目描述\n\n    给定两个整数 n 和 k，返回从 1 到 n 中选出 k 个数的所有组合。为了便于判题，输出按字典序排列。\n\n    ## 函数签名\n\n    - Java：`public List<List<Integer>> combine(int n, int k)`\n    - Python：`def combine(self, n, k)`\n\n    ## 输入格式\n\n    输入一行 n 和 k。\n\n    ## 输出格式\n\n    输出所有组合，格式为 [[1,2],[1,3]]；没有组合输出 []。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    4 2\n    ~~~\n\n    输出：\n\n    ~~~text\n    [[1,2],[1,3],[1,4],[2,3],[2,4],[3,4]]\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 20\n- 0 <= k <= n', 'MEDIUM', '输入一行 n 和 k。', '输出所有组合，格式为 [[1,2],[1,3]]；没有组合输出 []。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3016, 2008, '电话号码的字母组合', '## 题目描述\n\n    给定由数字 2 到 9 组成的字符串，返回它能表示的所有字母组合。映射关系与手机九宫格一致。输出按字典序排列。\n\n    ## 函数签名\n\n    - Java：`public List<String> letterCombinations(String digits)`\n    - Python：`def letterCombinations(self, digits)`\n\n    ## 输入格式\n\n    输入一行字符串 digits。空串用空行表示。\n\n    ## 输出格式\n\n    输出字符串数组格式，例如 [ad,ae,af]；空结果输出 []。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    23\n    ~~~\n\n    输出：\n\n    ~~~text\n    [ad,ae,af,bd,be,bf,cd,ce,cf]\n    ~~~\n\n    ## 数据范围\n\n    - 0 <= digits.length <= 4\n- digits 只包含 2-9', 'MEDIUM', '输入一行字符串 digits。空串用空行表示。', '输出字符串数组格式，例如 [ad,ae,af]；空结果输出 []。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3017, 2009, '分发饼干', '## 题目描述\n\n    每个孩子有胃口值，每块饼干有尺寸。每个孩子最多得到一块饼干，若饼干尺寸不小于胃口值则该孩子满足。返回最多能满足的孩子数量。\n\n    ## 函数签名\n\n    - Java：`public int findContentChildren(int[] g, int[] s)`\n    - Python：`def findContentChildren(self, g, s)`\n\n    ## 输入格式\n\n    第一行输入孩子数量 n；第二行输入 n 个胃口值；第三行输入饼干数量 m；第四行输入 m 个饼干尺寸。\n\n    ## 输出格式\n\n    输出最多满足的孩子数量。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    3\n1 2 3\n2\n1 1\n    ~~~\n\n    输出：\n\n    ~~~text\n    1\n    ~~~\n\n    ## 数据范围\n\n    - 0 <= n, m <= 30000\n- 数值为非负整数', 'EASY', '第一行输入孩子数量 n；第二行输入 n 个胃口值；第三行输入饼干数量 m；第四行输入 m 个饼干尺寸。', '输出最多满足的孩子数量。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3018, 2009, '跳跃游戏', '## 题目描述\n\n    给定一个非负整数数组，数组中每个元素表示在该位置最多可以向右跳的步数。判断是否能够从第一个位置到达最后一个位置。\n\n    ## 函数签名\n\n    - Java：`public boolean canJump(int[] nums)`\n    - Python：`def canJump(self, nums)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 n 个非负整数。\n\n    ## 输出格式\n\n    可以到达输出 true，否则输出 false。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    5\n2 3 1 1 4\n    ~~~\n\n    输出：\n\n    ~~~text\n    true\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 100000\n- 0 <= nums[i] <= 100000', 'MEDIUM', '第一行输入 n；第二行输入 n 个非负整数。', '可以到达输出 true，否则输出 false。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3019, 2010, '爬楼梯', '## 题目描述\n\n每次可以爬 1 级或 2 级台阶。给定台阶数 n，返回到达楼顶的不同方法数。\n\n## 函数签名\n\n- Java：`public int climbStairs(int n)`\n- Python：`def climbStairs(self, n)`\n\n## 输入格式\n\n输入一个整数 n。\n\n## 输出格式\n\n输出方法数。\n\n## 样例\n\n输入：\n\n~~~text\n3\n~~~\n\n输出：\n\n~~~text\n3\n~~~\n\n## 数据范围\n\n- 1 <= n <= 45', 'EASY', '输入一个整数 n。', '输出方法数。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3020, 2010, '最大子数组和', '## 题目描述\n\n    给定一个整数数组，找出和最大的连续非空子数组，并返回其最大和。\n\n    ## 函数签名\n\n    - Java：`public int maxSubArray(int[] nums)`\n    - Python：`def maxSubArray(self, nums)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 n 个整数。\n\n    ## 输出格式\n\n    输出最大连续子数组和。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    9\n-2 1 -3 4 -1 2 1 -5 4\n    ~~~\n\n    输出：\n\n    ~~~text\n    6\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 100000\n- -10^4 <= nums[i] <= 10^4', 'MEDIUM', '第一行输入 n；第二行输入 n 个整数。', '输出最大连续子数组和。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3021, 2011, '每日温度', '## 题目描述\n\n    给定每天的温度，返回一个数组，其中第 i 个元素表示需要等待多少天才会出现更高温度；如果之后不会升高，则为 0。\n\n    ## 函数签名\n\n    - Java：`public int[] dailyTemperatures(int[] temperatures)`\n    - Python：`def dailyTemperatures(self, temperatures)`\n\n    ## 输入格式\n\n    第一行输入 n；第二行输入 n 个温度。\n\n    ## 输出格式\n\n    输出等待天数数组，使用空格分隔。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    8\n73 74 75 71 69 72 76 73\n    ~~~\n\n    输出：\n\n    ~~~text\n    1 1 4 2 1 1 0 0\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n <= 100000\n- 30 <= temperature <= 100', 'MEDIUM', '第一行输入 n；第二行输入 n 个温度。', '输出等待天数数组，使用空格分隔。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3022, 2011, '下一个更大元素 I', '## 题目描述\n\n    nums1 是 nums2 的子集。对 nums1 中每个元素，找到它在 nums2 中右侧第一个更大的元素；如果不存在则为 -1。\n\n    ## 函数签名\n\n    - Java：`public int[] nextGreaterElement(int[] nums1, int[] nums2)`\n    - Python：`def nextGreaterElement(self, nums1, nums2)`\n\n    ## 输入格式\n\n    第一行输入 n1；第二行输入 nums1；第三行输入 n2；第四行输入 nums2。\n\n    ## 输出格式\n\n    输出每个 nums1 元素对应的下一个更大元素，使用空格分隔。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    3\n4 1 2\n4\n1 3 4 2\n    ~~~\n\n    输出：\n\n    ~~~text\n    -1 3 -1\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= n1 <= n2 <= 10000\n- 元素互不相同', 'EASY', '第一行输入 n1；第二行输入 nums1；第三行输入 n2；第四行输入 nums2。', '输出每个 nums1 元素对应的下一个更大元素，使用空格分隔。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0),
    (3023, 2012, '岛屿数量', '## 题目描述\n\n    给定由字符 0 和 1 组成的网格，1 表示陆地，0 表示水域。上下左右相邻的陆地属于同一个岛屿，返回岛屿数量。\n\n    ## 函数签名\n\n    - Java：`public int numIslands(char[][] grid)`\n    - Python：`def numIslands(self, grid)`\n\n    ## 输入格式\n\n    第一行输入 m 和 n；接下来 m 行每行输入长度为 n 的 01 字符串。\n\n    ## 输出格式\n\n    输出岛屿数量。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    4 5\n11110\n11010\n11000\n00000\n    ~~~\n\n    输出：\n\n    ~~~text\n    1\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= m, n <= 300\n- grid[i][j] 为 0 或 1', 'MEDIUM', '第一行输入 m 和 n；接下来 m 行每行输入长度为 n 的 01 字符串。', '输出岛屿数量。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 1, 0),
    (3024, 2012, '课程表', '## 题目描述\n\n    给定课程数量和先修关系，判断是否可以完成所有课程。关系 [a,b] 表示学习 a 之前必须先学习 b。\n\n    ## 函数签名\n\n    - Java：`public boolean canFinish(int numCourses, int[][] prerequisites)`\n    - Python：`def canFinish(self, numCourses, prerequisites)`\n\n    ## 输入格式\n\n    第一行输入 numCourses 和 m；接下来 m 行每行输入 a b，表示一条先修关系。\n\n    ## 输出格式\n\n    可以完成所有课程输出 true，否则输出 false。\n\n    ## 样例\n\n    输入：\n\n    ~~~text\n    2 1\n1 0\n    ~~~\n\n    输出：\n\n    ~~~text\n    true\n    ~~~\n\n    ## 数据范围\n\n    - 1 <= numCourses <= 2000\n- 0 <= m <= 5000', 'MEDIUM', '第一行输入 numCourses 和 m；接下来 m 行每行输入 a b，表示一条先修关系。', '可以完成所有课程输出 true，否则输出 false。', 'java,python', 1000, 256, 'PUBLISHED', 0, 0, 2, 0);
