-- FlowStudy learning content seed: algorithm topic set with LeetCode-style function signatures
-- Topic order is inspired by Code Thinking / 代码随想录, but titles, descriptions, examples and tests are original seed content.
-- This script stores LeetCode-style wrapper metadata in fs_code_template.judge_wrapper_code as JSON.
USE flowstudy;
SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci;
SET FOREIGN_KEY_CHECKS = 0;

