SET FOREIGN_KEY_CHECKS = 1;

-- Validation queries
SELECT id, title, status FROM fs_tutorial WHERE id BETWEEN 1001 AND 1999 ORDER BY id;
SELECT id, tutorial_id, title, status FROM fs_blog WHERE id BETWEEN 2001 AND 2999 ORDER BY id;
SELECT id, blog_id, title, difficulty FROM fs_problem WHERE id BETWEEN 3001 AND 3999 ORDER BY id;
SELECT problem_id, COUNT(*) AS testcase_count FROM fs_problem_testcase WHERE problem_id BETWEEN 3001 AND 3999 GROUP BY problem_id;
SELECT problem_id, language FROM fs_code_template WHERE problem_id BETWEEN 3001 AND 3999 ORDER BY problem_id, language;